import{_ as a,o as s,c as t,ag as i}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Quick Start","description":"Get Foldergram running locally with a real gallery structure and verified defaults.","frontmatter":{"title":"Quick Start","description":"Get Foldergram running locally with a real gallery structure and verified defaults."},"headers":[],"relativePath":"quick-start.md","filePath":"quick-start.md","lastUpdated":1775244546000}'),n={name:"quick-start.md"};function l(o,e,p,r,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Docker Compose is the recommended way to run Foldergram.</p><p>It gives you the quickest path to a working install and includes the media tooling needed for video support, so you do not need to set up Node.js, <code>pnpm</code>, or <code>ffmpeg</code> on the host first.</p><h2 id="preferred-docker-compose" tabindex="-1">Preferred: Docker Compose <a class="header-anchor" href="#preferred-docker-compose" aria-label="Permalink to &quot;Preferred: Docker Compose&quot;">​</a></h2><h2 id="_1-create-your-local-data-layout" tabindex="-1">1. Create your local data layout <a class="header-anchor" href="#_1-create-your-local-data-layout" aria-label="Permalink to &quot;1. Create your local data layout&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>  gallery/</span></span>
<span class="line"><span>  db/</span></span>
<span class="line"><span>  thumbnails/</span></span>
<span class="line"><span>  previews/</span></span></code></pre></div><h2 id="_2-put-media-into-folders-under-data-gallery" tabindex="-1">2. Put media into folders under <code>data/gallery</code> <a class="header-anchor" href="#_2-put-media-into-folders-under-data-gallery" aria-label="Permalink to &quot;2. Put media into folders under \`data/gallery\`&quot;">​</a></h2><p>Foldergram does not index loose files placed directly in the gallery root.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>  gallery/</span></span>
<span class="line"><span>    trips/</span></span>
<span class="line"><span>      oslo/</span></span>
<span class="line"><span>        IMG_0001.jpg</span></span>
<span class="line"><span>        clip-01.mp4</span></span>
<span class="line"><span>    family/</span></span>
<span class="line"><span>      summer-2024/</span></span>
<span class="line"><span>        porch.webp</span></span></code></pre></div><p>The important rule is simple:</p><ul><li>A non-hidden folder becomes an indexed album only when it directly contains supported media.</li><li>Nested folders become separate albums if they directly contain media.</li></ul><p>Optional: add folder stories and highlights with a reserved <code>stories/</code> folder:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>  gallery/</span></span>
<span class="line"><span>    AnimalPlanet/</span></span>
<span class="line"><span>      post-1.jpg</span></span>
<span class="line"><span>      stories/</span></span>
<span class="line"><span>        story-1.mp4</span></span>
<span class="line"><span>        story-2.jpg</span></span>
<span class="line"><span>        Lions/</span></span>
<span class="line"><span>          clip-1.mp4</span></span>
<span class="line"><span>          nested-1/</span></span>
<span class="line"><span>            clip-2.jpg</span></span></code></pre></div><p>In the default mode:</p><ul><li>direct media inside <code>AppFolder/stories</code> powers the folder avatar story</li><li>each direct child folder under <code>stories/</code> becomes one highlight circle</li><li>nested folders stay inside that same highlight capsule</li></ul><p>If you need folders literally named <code>stories</code> to behave like normal app folders, open <code>Settings -&gt; General Settings</code>, enable <code>Treat stories folders as normal app folders</code>, then run a rescan from <code>Settings -&gt; Scan &amp; Library</code>.</p><h2 id="_3-start-the-container" tabindex="-1">3. Start the container <a class="header-anchor" href="#_3-start-the-container" aria-label="Permalink to &quot;3. Start the container&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>The included compose file:</p><ul><li>uses the GHCR image by default</li><li>maps host port <code>4141</code> by default</li><li>mounts <code>./data/gallery</code>, <code>./data/db</code>, <code>./data/thumbnails</code>, and <code>./data/previews</code></li><li>runs the app in production mode</li><li>uses internal container paths under <code>/app/data</code></li><li>relies on the image&#39;s bundled <code>ffmpeg</code></li></ul><p>For the default Docker Compose setup, the container uses the image&#39;s built-in production defaults plus the mounted <code>./data/...</code> volumes. The source-install <code>.env</code> file is not read directly inside the container.</p><p>The shipped Compose file sets <code>IMAGE_DETAIL_SOURCE=preview</code> and <code>DERIVATIVE_MODE=eager</code>.</p><p>If you want Docker to skip specific source folders from the start, also add <code>GALLERY_EXCLUDED_FOLDERS</code> in <code>docker-compose.yml</code>, for example:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">GALLERY_EXCLUDED_FOLDERS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@eaDir,thumbnails,Archive/cache&quot;</span></span></code></pre></div><p>For an optional read-only public demo in Docker, add <code>PUBLIC_DEMO_MODE=&quot;1&quot;</code> under the Compose <code>environment:</code> block. If the browser-visible origin differs from the upstream Node host, also set <code>CSRF_TRUSTED_ORIGINS</code> to that public origin.</p><p>If you cloned the repo and want to build locally instead, use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.yml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.local.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span></span></code></pre></div><h2 id="_4-open-the-app" tabindex="-1">4. Open the app <a class="header-anchor" href="#_4-open-the-app" aria-label="Permalink to &quot;4. Open the app&quot;">​</a></h2><ul><li><code>http://localhost:4141</code> for the app</li><li><code>http://localhost:4141/api/health</code> for a quick backend check</li></ul><p>On first run, the server performs a startup scan because there is no existing index. Existing libraries keep using the current index on startup; run <code>Scan Library</code> from Settings whenever you want to refresh the library after changes.</p><p>If you want the lowest upfront derivative work for a large library in Docker, edit <code>docker-compose.yml</code> before startup:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IMAGE_DETAIL_SOURCE=original</span></span>
<span class="line"><span>DERIVATIVE_MODE=lazy</span></span></code></pre></div><p>That combination keeps image detail pages on originals and generates missing thumbnails or previews only when they are first requested.</p><p>If you plan to expose Foldergram on a homelab or LAN, open Settings after the first load and enable the admin password. From there, you can keep admin-only access, add a separate viewer password, or switch to public browse mode.</p><p>Inside Settings:</p><ul><li><code>General Settings</code> contains stories mode, excluded folders, and Home/Reels defaults</li><li><code>Scan &amp; Library</code> contains manual scan plus rebuild actions</li></ul><p>Until you enable password protection, Foldergram starts without an auth gate, so Settings and the library-maintenance controls are available immediately to whoever can reach the app.</p><h2 id="optional-run-from-source-for-development" tabindex="-1">Optional: run from source for development <a class="header-anchor" href="#optional-run-from-source-for-development" aria-label="Permalink to &quot;Optional: run from source for development&quot;">​</a></h2><p>Foldergram is a <code>pnpm</code> workspace monorepo with three workspaces:</p><ul><li><code>server</code></li><li><code>client</code></li><li><code>docs</code></li></ul><p>Use the source workflow when you want to develop or modify the app itself.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requirement</th><th>Notes</th></tr></thead><tbody><tr><td>Node.js 22</td><td>The repo is configured for Node 22.</td></tr><tr><td><code>pnpm</code></td><td>Matches the workspace scripts and lockfile.</td></tr><tr><td>FFmpeg and FFprobe</td><td>Required on the host if you run the app outside Docker and want video support.</td></tr></tbody></table><h3 id="development-startup" tabindex="-1">Development startup <a class="header-anchor" href="#development-startup" aria-label="Permalink to &quot;Development startup&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>This runs:</p><ul><li>the Vite client on <code>http://localhost:4141</code>, with automatic fallback through <code>4144</code></li><li>the Express server on <code>http://localhost:4140</code></li><li>the VitePress docs site on <code>http://localhost:4145</code>, with automatic fallback to the next free port</li></ul><h2 id="useful-commands" tabindex="-1">Useful commands <a class="header-anchor" href="#useful-commands" aria-label="Permalink to &quot;Useful commands&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> down</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rescan</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:docs</span></span></code></pre></div><h2 id="what-to-expect-after-startup" tabindex="-1">What to expect after startup <a class="header-anchor" href="#what-to-expect-after-startup" aria-label="Permalink to &quot;What to expect after startup&quot;">​</a></h2><ul><li>Feed, folder pages, likes, explore, and moments read from SQLite, not directly from disk.</li><li>Thumbnails are generated under <code>data/thumbnails</code>.</li><li>Previews are generated under <code>data/previews</code>.</li><li>In the default unprotected state, Settings is available immediately.</li><li>After access protection is enabled, only admin sessions can open Settings or run scan and rebuild actions. Viewer and public sessions stay browse-only.</li></ul><p>If nothing appears, start with <a href="/troubleshooting">Troubleshooting</a>.</p>`,52)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
